{"mac":"[
    {
        "key": "alt+a",
        "command": "workbench.action.debug.start",
        "when": "editorTextFocus && resourceLangId == python && !inDebugMode"
    },
    {
        "key": "alt+s",
        "command": "workbench.action.debug.stop",
        "when": "inDebugMode"
    },
]","linux":"// Place your key bindings in this file to override the defaults
[
  // -------------------------------------------------------
  // DISABLE conflicting VS Code Alt defaults first
  // -------------------------------------------------------
  { "key": "alt+i", "command": "-editor.action.insertSnippet" },
  { "key": "alt+d", "command": "-editor.action.addSelectionToNextFindMatch" },
  { "key": "alt+f", "command": "-actions.findWithArgs" },
  { "key": "alt+j", "command": "-toggleFindCaseSensitive" },
  { "key": "alt+k", "command": "-editor.action.trimTrailingWhitespace" },
  { "key": "alt+l", "command": "-expandLineSelection" },
  { "key": "alt+s", "command": "-workbench.action.files.saveAll" },
  { "key": "alt+e", "command": "-workbench.view.explorer" },
  { "key": "alt+u", "command": "-editor.action.transformToUppercase" },
  { "key": "alt+o", "command": "-workbench.action.openSettingsJson" },
  { "key": "alt+y", "command": "-redo" },
  { "key": "alt+h", "command": "-editor.action.startFindReplaceAction" },
  { "key": "alt+m", "command": "-editor.action.toggleTabFocusMode" },

  // -------------------------------------------------------
  // Basic cursor movement (Alt+I/K/J/L)
  // -------------------------------------------------------
  { "key": "alt+i", "command": "cursorUp",    "when": "editorTextFocus" },
  { "key": "alt+k", "command": "cursorDown",  "when": "editorTextFocus" },
  { "key": "alt+j", "command": "cursorLeft",  "when": "editorTextFocus" },
  { "key": "alt+l", "command": "cursorRight", "when": "editorTextFocus" },

  // -------------------------------------------------------
  // Cursor selection (Alt+Shift+I/K/J/L)
  // -------------------------------------------------------
  { "key": "alt+shift+i", "command": "cursorUpSelect",    "when": "editorTextFocus" },
  { "key": "alt+shift+k", "command": "cursorDownSelect",  "when": "editorTextFocus" },
  { "key": "alt+shift+j", "command": "cursorLeftSelect",  "when": "editorTextFocus" },
  { "key": "alt+shift+l", "command": "cursorRightSelect", "when": "editorTextFocus" },

  // -------------------------------------------------------
  // Word jump (Alt+Ctrl+J/L)
  // -------------------------------------------------------
  { "key": "alt+ctrl+j", "command": "cursorWordLeft",  "when": "editorTextFocus" },
  { "key": "alt+ctrl+l", "command": "cursorWordRight", "when": "editorTextFocus" },

  // Word jump + select (Alt+Ctrl+Shift+J/L)
  { "key": "alt+ctrl+shift+j", "command": "cursorWordLeftSelect",  "when": "editorTextFocus" },
  { "key": "alt+ctrl+shift+l", "command": "cursorWordRightSelect", "when": "editorTextFocus" },

  // -------------------------------------------------------
  // File top / bottom (Alt+Ctrl+I/K)
  // -------------------------------------------------------
  { "key": "alt+ctrl+i", "command": "cursorTop",    "when": "editorTextFocus" },
  { "key": "alt+ctrl+k", "command": "cursorBottom", "when": "editorTextFocus" },

  // File top / bottom select (Alt+Ctrl+Shift+I/K)
  { "key": "alt+ctrl+shift+i", "command": "cursorTopSelect",    "when": "editorTextFocus" },
  { "key": "alt+ctrl+shift+k", "command": "cursorBottomSelect", "when": "editorTextFocus" },

  // -------------------------------------------------------
  // Line home / end (Alt+U/O)
  // -------------------------------------------------------
  { "key": "alt+u", "command": "cursorHome", "when": "editorTextFocus" },
  { "key": "alt+o", "command": "cursorEnd",  "when": "editorTextFocus" },

  // Line home / end select (Alt+Shift+U/O)
  { "key": "alt+shift+u", "command": "cursorHomeSelect", "when": "editorTextFocus" },
  { "key": "alt+shift+o", "command": "cursorEndSelect",  "when": "editorTextFocus" },

  // -------------------------------------------------------
  // Scrolling (Alt+E/D)
  // -------------------------------------------------------
  { "key": "alt+e", "command": "scrollLineUp",   "when": "editorTextFocus" },
  { "key": "alt+d", "command": "scrollLineDown", "when": "editorTextFocus" },

  // -------------------------------------------------------
  // Delete word (Alt+Backspace / Alt+Delete)
  // -------------------------------------------------------
  { "key": "alt+backspace", "command": "deleteWordLeft",  "when": "editorTextFocus" },
  { "key": "alt+delete",    "command": "deleteWordRight", "when": "editorTextFocus" },

  // -------------------------------------------------------
  // Duplicate line (Alt+Shift+D)
  // -------------------------------------------------------
  { "key": "alt+shift+d", "command": "editor.action.copyLinesDownAction", "when": "editorTextFocus" },

  // -------------------------------------------------------
  // Move line up/down (Alt+Shift+E / Alt+Shift+X)
  // -------------------------------------------------------
  { "key": "alt+shift+e", "command": "editor.action.moveLinesUpAction",   "when": "editorTextFocus" },
  { "key": "alt+shift+x", "command": "editor.action.moveLinesDownAction", "when": "editorTextFocus" },

  // -------------------------------------------------------
  // Tab switching (Alt+H / Alt+;)
  // -------------------------------------------------------
  { "key": "alt+h",         "command": "workbench.action.previousEditor" },
  { "key": "alt+semicolon", "command": "workbench.action.nextEditor" },

  // Move editor to group (Alt+Shift+H / Alt+Shift+;)
  { "key": "alt+shift+h",         "command": "workbench.action.moveEditorToPreviousGroup" },
  { "key": "alt+shift+semicolon", "command": "workbench.action.moveEditorToNextGroup" },

  // -------------------------------------------------------
  // Pin tab (Alt+Y)
  // -------------------------------------------------------
  { "key": "alt+y", "command": "workbench.action.pinEditor" },

  // -------------------------------------------------------
  // Multi-cursor (Alt+M / Alt+Shift+M)
  // -------------------------------------------------------
  { "key": "alt+m",       "command": "editor.action.insertCursorAbove", "when": "editorTextFocus" },
  { "key": "alt+shift+m", "command": "editor.action.insertCursorBelow", "when": "editorTextFocus" },

  // -------------------------------------------------------
  // Super (meta) — editor/window management
  // -------------------------------------------------------
  { "key": "meta+q",     "command": "workbench.action.closeActiveEditor" },
  { "key": "meta+f",     "command": "workbench.action.toggleZenMode" },
  { "key": "meta+m",     "command": "workbench.action.toggleMaximizeEditorGroup" },
  { "key": "meta+t",     "command": "workbench.action.terminal.toggleTerminal" },
  { "key": "meta+e",     "command": "workbench.view.explorer" },
  { "key": "meta+b",     "command": "workbench.action.toggleSidebarVisibility" },
  { "key": "meta+d",     "command": "workbench.action.showCommands" },
  { "key": "meta+enter", "command": "workbench.action.terminal.toggleTerminal" },

  // Focus between editor groups (Super+Arrows)
  { "key": "meta+left",  "command": "workbench.action.focusLeftGroup" },
  { "key": "meta+right", "command": "workbench.action.focusRightGroup" },
  { "key": "meta+up",    "command": "workbench.action.focusAboveGroup" },
  { "key": "meta+down",  "command": "workbench.action.focusBelowGroup" },

  // Resize editor groups (Super+Shift+Arrows)
  { "key": "meta+shift+right", "command": "workbench.action.increaseViewWidth" },
  { "key": "meta+shift+left",  "command": "workbench.action.decreaseViewWidth" },
  { "key": "meta+shift+down",  "command": "workbench.action.increaseViewHeight" },
  { "key": "meta+shift+up",    "command": "workbench.action.decreaseViewHeight" },

  // Move editor group (Super+Ctrl+Arrows)
  { "key": "meta+ctrl+left",  "command": "workbench.action.moveActiveEditorGroupLeft" },
  { "key": "meta+ctrl+right", "command": "workbench.action.moveActiveEditorGroupRight" },

  // Jump to tab by number (Super+1..9)
  { "key": "meta+1", "command": "workbench.action.openEditorAtIndex1" },
  { "key": "meta+2", "command": "workbench.action.openEditorAtIndex2" },
  { "key": "meta+3", "command": "workbench.action.openEditorAtIndex3" },
  { "key": "meta+4", "command": "workbench.action.openEditorAtIndex4" },
  { "key": "meta+5", "command": "workbench.action.openEditorAtIndex5" },
  { "key": "meta+6", "command": "workbench.action.openEditorAtIndex6" },
  { "key": "meta+7", "command": "workbench.action.openEditorAtIndex7" },
  { "key": "meta+8", "command": "workbench.action.openEditorAtIndex8" },
  { "key": "meta+9", "command": "workbench.action.openEditorAtIndex9" },

  // Settings / reload (Super+Ctrl+S/R/K)
  { "key": "meta+ctrl+s", "command": "workbench.action.openSettings" },
  { "key": "meta+ctrl+r", "command": "workbench.action.reloadWindow" },
  { "key": "meta+ctrl+k", "command": "workbench.action.openGlobalKeybindings" }
]"}
